--[[

local EnvLoggerCheck = loadstring(game:HttpGet("https://raw.githubusercontent.com/highskyY8K/roblox-scripts/main/AntiEnvLogger.lua"))()

if not EnvLoggerCheck then
	--Ur script here.
else
	--The else is optional, you can add a teasing message here. xD
end

]]
